@namespace Lumeo
@typeparam T
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop

<div class="@CssClass" role="tree" aria-multiselectable="@MultiSelect.ToString().ToLowerInvariant()" @attributes="AdditionalAttributes">
    @if (ShowSearch)
    {
        <div class="mb-2">
            <input type="text" placeholder="@L["Common.Search"]"
                   class="flex h-8 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                   value="@_searchText"
                   @oninput="OnSearchInput" />
        </div>
    }

    @if (Items is { Count: > 0 })
    {
        <CascadingValue Value="_context" IsFixed="false">
            @for (var i = 0; i < _displayItems.Count; i++)
            {
                var item = _displayItems[i];
                <TreeViewNode T="T" @key="item" Item="item" Level="0"
                              PosInSet="@(i + 1)"
                              SetSize="@_displayItems.Count"
                              ShowCheckboxes="ShowCheckboxes"
                              Expandable="Expandable"
                              CascadeCheck="CascadeCheck"
                              MultiSelect="MultiSelect"
                              ExpandOnRowClick="ExpandOnRowClick"
                              SelectedNodes="_selectedNodes"
                              NodeTemplate="NodeTemplate"
                              LoadChildren="LoadChildren"
                              OnItemClick="HandleItemClick"
                              OnItemCheck="HandleItemCheck"
                              OnExpandChanged="HandleExpandChanged"
                              OnSelectionChanged="HandleSelectionChanged" />
            }
        </CascadingValue>
    }
</div>

@code {
    [Parameter] public List<TreeViewItem<T>>? Items { get; set; }
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; } = true;
    /// <summary>
    /// When <c>true</c> (the default), clicking anywhere on a parent row — a node that has, or
    /// can lazily load, children — both selects it AND toggles its expansion (the whole row is
    /// the expand/collapse target, giving a large hit/touch area; the VS Code file-tree pattern).
    /// Leaf rows always just select. Set to <c>false</c> to keep the chevron as the sole expand
    /// trigger, so a row click only selects. The chevron and keyboard (ArrowRight/Left) expand in
    /// both modes; a Ctrl/Meta/Shift (multi-select modifier) click only selects, never expands.
    /// Has no effect when <see cref="Expandable"/> is <c>false</c>.
    /// </summary>
    [Parameter] public bool ExpandOnRowClick { get; set; } = true;
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemCheck { get; set; }
    [Parameter] public bool ShowSearch { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    [Parameter] public Func<TreeViewItem<T>, Task<List<TreeViewItem<T>>>>? LoadChildren { get; set; }
    [Parameter] public bool CascadeCheck { get; set; } = true;
    [Parameter] public EventCallback<List<T?>> CheckedValuesChanged { get; set; }
    [Parameter] public RenderFragment<TreeViewItem<T>>? NodeTemplate { get; set; }
    [Parameter] public bool ExpandAll { get; set; }
    [Parameter] public bool MultiSelect { get; set; }
    [Parameter] public List<T>? SelectedValues { get; set; }
    [Parameter] public EventCallback<List<T>> SelectedValuesChanged { get; set; }

    private string _searchText = "";
    private List<TreeViewItem<T>>? _previousItems;
    // #14: last SelectedValues reference we seeded from, so we only re-seed when
    // the parameter actually changes (not on every unrelated re-render).
    private List<T>? _previousSelectedValues;
    // CONTROLLED discriminator: the last SelectedValues list reference we pushed UP
    // via SelectedValuesChanged. A controlled parent re-render that echoes back this
    // same object reference (the parent simply re-supplies what we handed it) is
    // safe to ignore (keep the in-flight _selectedValues); any OTHER reference — a
    // veto that restores the pre-interaction selection, a programmatic reset, or an
    // externally-applied selection — is an authoritative assertion and must win.
    private List<T>? _lastPushedSelectedValues;
    private bool _previousExpandAll;
    private List<TreeViewItem<T>> _displayItems = [];
    // ══════════════════════════════════════════════════════════════════════════
    // CANONICAL POST-AWAIT RE-RESOLUTION MODEL (PR #351, round-11 consolidation)
    // ══════════════════════════════════════════════════════════════════════════
    // Every row-click / lazy-load path may run its tail AFTER an await, during which a
    // controlled/immutable consumer can rebuild Items (disposing the @key'd instance the
    // interaction started on). Six rounds accreted a separate resolver per tail — a relaxed
    // positional expansion fallback, distinct rollback/success/selection resolvers, a deferred
    // toggle, seeded-vs-interactive carry buckets — and round-11 found four more edges in the
    // seams. This is ONE model; the special cases are gone.
    //
    // (1) NODE RE-RESOLUTION — exactly one function, ResolveNode(instance, path, value, mode),
    //     used by ALL post-await paths (selection changed / click-path re-resolution, expansion
    //     success attach, expansion failure rollback, search auto-expand collapse). Priority,
    //     identical for every mode:
    //        a. ReferenceEquals — the instance is still in the tree (no rebuild / untouched
    //           branch): return it.
    //        b. VALUE-VERIFIED PATH — the node at `path` still carries `value` AND that value is UNIQUE
    //           among its immediate siblings, VALIDATED AT EVERY SEGMENT (round-13 b): each ancestor index
    //           must also land on a node whose recorded value is sibling-unique at that level. WalkPath now
    //           carries a per-level value chain (NodePath), so a shared/duplicate/null value at ANY segment
    //           — ancestor or leaf — is NOT a provable anchor (a silent sibling reorder is indistinguishable
    //           from a same-content reload) and the whole path drops here. This closes the ancestor hole:
    //           two duplicate/null-valued ancestor folders reordered, each holding a same-valued child,
    //           previously let a leaf-only check walk into the WRONG subtree and pass.
    //        c. TREE-UNIQUE VALUE — exactly one node in the whole tree carries `value` (a node
    //           that merely moved): return it.
    //        d. MODE TAIL — both modes DROP (return null). There is NO positional guess:
    //           • SELECTION drop  → the click selects nothing new; the identity is unprovable and
    //             mis-selecting a same-valued sibling is a real defect (round-11 a). The prior
    //             selection minus the vanished node stands.
    //           • EXPANSION drop  → the loaded children are DISCARDED, not grafted onto whatever
    //             duplicate/null-valued sibling now sits at the old index. A rebuild can REORDER
    //             same-valued container rows while LoadChildren is in flight, and duplicate
    //             container values do NOT guarantee equivalent children (round-11 b), so a
    //             positional attach is unsound. Tradeoff, stated: re-fetchable children (the
    //             branch stays ChildrenLoaded=false and reloads on the next expand) beat a silent
    //             mis-attachment. Failure rollback likewise collapses ONLY a node it can resolve
    //             by (a)–(c); a genuinely ambiguous node is left for the consumer's own rebuild.
    //     The former relaxed WalkPath(requireSiblingUnique:false) fallback is DELETED.
    //
    // (2) DEFERRAL ORDERING CONTRACT for a row click (HandleClick):
    //        i.   SYNCHRONOUS state flip on the LIVE instance (IsExpanded, and for a lazy expand
    //             IsLoading + a path snapshot) — before any await, so a selection-driven rebuild
    //             snapshots the new state off THIS instance (round-4).
    //        ii.  selection callbacks: OnItemClick then OnSelectionChanged (may rebuild Items).
    //        iii. the expansion TAIL, drained isolated (a loader failure cannot break the
    //             already-committed selection). The tail STARTS the load here — never before
    //             selection — so even a cached/completed loader task (Task.FromResult) attaches
    //             through ResolveNode to the REBUILT node instead of the disposed one (round-10).
    //             A collapse tail re-resolves through ResolveNode before clearing IsExpanded and
    //             _autoExpanded (CollapseReanchored), so a search-auto-expanded ancestor collapses
    //             the FRESH item RebuildDisplay re-registered, not the stale reference (round-11 c).
    //             Failure rolls back via ResolveNode (round-7/8).
    //
    // (3) CHANGE DETECTION — re-resolution must NOT hinge on Items list-reference identity.
    //     The reanchor/pending/tri-state pass runs when the reference changed OR
    //     HasStaleOrPendingSelection() reports a possibly-stale binding (a _selectedNodes instance
    //     no longer in the tree, or a non-empty pending bucket). So an IN-PLACE mutation of the
    //     same list reference — replacing items[i] with a fresh same-valued node — still reanchors
    //     the selection onto the new instance (round-11 d). Cost: HasStaleOrPendingSelection
    //     flattens the tree O(n), but only on a SAME-reference re-render that also holds a
    //     selection/pending state; a selection-free tree or a reference swap pays nothing extra.
    //     FILTERED DISPLAY (round-13 a): while a search filter is active _displayItems is a SEPARATE
    //     filtered ToList() snapshot, so it goes stale on an in-place retitle/replace even when there is NO
    //     selection to make needsResolve fire. The filtered display is therefore ALSO re-materialized
    //     whenever a filter is active and neither the Items reference nor ExpandAll changed —
    //     unconditionally, not gated on selection. Tradeoff: an O(n) re-filter on every OnParametersSet
    //     while a filter is live (simpler + cheaper than a structural fingerprint; RebuildDisplay is
    //     idempotent, so a redundant rebuild loses no state).
    //
    // (4) SETTLED SEMANTICS (unchanged, see the lifecycle notes below): seeded=VALUE contract
    //     (re-binds every match, additive across lazy loads) vs interactive=IDENTITY (carry by
    //     value-verified path, strict ambiguity DROP); tri-state derive-on-seed gating
    //     (CascadeCheck && ShowCheckboxes); ExpandOnRowClick opt-out; chevron/keyboard expansion in
    //     both modes; loader-failure rollback that stays retryable (ChildrenLoaded=false).
    //
    // (5) IN-FLIGHT OWNERSHIP (round-12) — the optimistic in-flight flags (IsLoading, and the pre-load
    //     IsExpanded a lazy expand sets before its children arrive) may persist on a node ONLY while an
    //     operation the tree started still OWNS that node. Every lazy load REGISTERS an ownership entry
    //     the instant it sets IsLoading — a snapshot of {index path, value, immediate-sibling values} —
    //     and REMOVES it when the load resolves by ANY outcome (success attach / ambiguous DROP /
    //     failure rollback), all via the finally (RegisterInFlightExpansion / CompleteInFlightExpansion;
    //     ExpandAll registers inline). A controlled/immutable rebuild that COPIES the flags onto a fresh
    //     @key'd instance (records copy by value) produces flags that NO code path owns once the
    //     originating op resolves. SweepOrphanedInFlightFlags runs after ANY resolution pass (the
    //     OnParametersSet reanchor block AND every load completion) and clears the flags of any node
    //     whose IsLoading has NO live entry claiming its slot (path+value+siblings) — collapsing the
    //     paired optimistic IsExpanded when nothing loaded. While the op is genuinely in flight its entry
    //     keeps the fresh node's spinner; the sweep only reaps AFTER the entry is gone. This is what makes
    //     the "drop the ambiguous load and re-fetch on the next expand" path reachable: the drop clears
    //     the copied spinner instead of stranding it forever (round-12 finding 1). Ownership uses a
    //     POSITIONAL (not identity-strict) slot match — clearing an orphaned spinner needs only "no op
    //     claims this slot", a strictly weaker question than ResolveNode's provable identity for data.
    //     SUPERSESSION (round-13 c): BeginToggleExpand sets the optimistic IsExpanded=true BEFORE awaiting a
    //     lazy load, so a collapse DURING the load (second row click / ArrowLeft / collapse-all) would be
    //     overwritten by the success path's unconditional IsExpanded=true. A collapse now marks the owning
    //     in-flight entry Superseded; the success completion still ATTACHES children (ChildrenLoaded=true)
    //     but SKIPS the re-expand, honoring the user's latest intent. EXPAND-ALL PARITY (round-13 d):
    //     LoadAndExpandAllAsync's lazy completion now re-resolves the target via ResolveExpansionTarget
    //     (drop-on-ambiguity → the branch re-fetches next expand), gates IsExpanded on supersession,
    //     descends the RESOLVED subtree, and SWEEPS in its finally — the SAME contract as the per-row
    //     LoadChildrenThenNotifyAsync path, so a rebuild mid-expand-all no longer strands a copied spinner
    //     on a fresh row or attaches children to a disposed instance (round-13 finding 4).
    //
    // (6) SELECTION-PATH SNAPSHOT (round-12) — ReanchorSelection reads a vanished node's OLD index path
    //     from _selectionPaths, a map snapshotted after every resolution pass, NOT from the outgoing
    //     Items list. For an IN-PLACE mutation _previousItems is the SAME object the consumer already
    //     mutated, so the departed node is no longer walkable there and a live-list BuildNodePath fails;
    //     the snapshot recorded the path while the node WAS present, so a duplicate-valued node that was
    //     path-identifiable among its siblings still reanchors instead of being dropped by the
    //     unique-value fallback (round-12 finding 2). The live list stays the fallback for the first pass
    //     (no snapshot yet).
    // ══════════════════════════════════════════════════════════════════════════
    // ── SELECTION LIFECYCLE ──────────────────────────────────────────────────
    // One coherent model, four states, driven by Items refreshes and clicks — NOT by
    // SelectedValues list-reference identity (that check only gates whether we RE-SEED
    // from the parameter; resolution/carry below run on every Items change regardless):
    //
    //   seed        a value the consumer supplied via SelectedValues (the durable
    //               source of truth for a controlled/seeded selection).
    //   pending     a wanted value with NO materialized node in the current tree
    //               (async/empty first render, or a lazy child not yet loaded). Held in
    //               _pendingSelectValues; awaits a tree that contains a matching node.
    //   resolved    a wanted (or interactively-chosen) value bound to a concrete node
    //               INSTANCE. Held in _selectedNodes by reference identity.
    //   superseded  a seed/pending value voided by an authoritative later assertion.
    //
    // Transitions (each names what it consumes / clears):
    //   seed → pending|resolved   ResolveSelectedNodes(new SelectedValues): matched
    //                             values → resolved; unmatched → pending. While the tree still
    //                             has UNLOADED lazy branches EVERY requested value — matched
    //                             included — also stays pending, so a same-valued node that later
    //                             materializes behind LoadChildren is still selected (the value
    //                             contract binds every match, not just the first visible one).
    //   pending → resolved        TryResolvePendingSelection(tree): a pending value whose
    //                             node has now materialized binds. Runs on ANY Items
    //                             refresh AND on lazy-load. Additive; never pushes up. A resolved
    //                             value is only PRUNED from pending once the tree is fully
    //                             materialized (no lazy branch left that could hold a duplicate);
    //                             until then it re-applies to each newly-loaded subtree.
    //   resolved → resolved′      ReanchorSelection on Items change: a resolved node
    //                             replaced by an equal instance re-anchors by path/value.
    //   resolved → pending        ReanchorSelection when a resolved node VANISHES from the
    //                             new tree (empty/null reload, or a lazy branch collapsed
    //                             back to unloaded): its structural IDENTITY — the same
    //                             value-verified index PATH the reanchor uses, carried
    //                             ALONGSIDE its value in _pendingCarries — is queued so the
    //                             SAME node re-binds when it reappears, even when its Value is a
    //                             duplicate or null. On return the entry PREFERS the path and
    //                             falls back to a UNIQUE value; a still-absent value stays queued
    //                             (a lazy branch not loaded yet), but once the path fails AND the
    //                             value is AMBIGUOUS the carry is DROPPED immediately — it never
    //                             re-selects a same-valued sibling, nor lingers to mis-bind the
    //                             wrong node on a later single-match refresh. (This, plus the
    //                             always-run TryResolvePending, is why the lifecycle survives a
    //                             same-reference reload.)
    //   pending/resolved → superseded   HandleSelectionChanged (interactive): single-select
    //                             — the click owns the whole selection, so ALL pending is
    //                             cleared (a stale seed can't resurrect + co-select once its
    //                             branch loads). multi-select — only the toggled value is
    //                             dropped from pending; the seed's other values stay wanted.
    //   any → reset               ResolveSelectedNodes(null/empty): clears both sets.
    //
    // ── TWO ORIGIN BUCKETS (round-9) ─────────────────────────────────────────
    // A selection is either SEEDED (it originated from a consumer SelectedValues value) or
    // INTERACTIVE (a click chose the node instance). The two survive an Items vanish/return by
    // DIFFERENT rules, so their origin is tracked (_seededValues) and they carry through separate
    // buckets:
    //   SEEDED       keeps VALUE semantics. When its node vanishes it is re-queued as a VALUE
    //                (_pendingSelectValues) and re-binds to EVERY match on return — the value
    //                contract — even for a duplicate/null value. Stays pending while lazy branches
    //                are unloaded (the round-7 machinery). Voided by a new SelectedValues.
    //   INTERACTIVE  keeps IDENTITY semantics. When its node vanishes it is carried as a structural
    //                IDENTITY (_pendingCarries: value-verified path + value) and re-binds the SAME
    //                node by path / UNIQUE value, DROPPING on ambiguity — it never lights up a
    //                same-valued sibling nor every match.
    // Transition: an interactive click on a SEEDED node converts it to interactive (single-select
    // clears ALL seeds; multi-select drops just the toggled value from the seed set), after which
    // that value follows the identity rules above. Without this split a value seed silently degraded
    // into an identity carry on an empty/async reload and its ambiguity rule then DROPPED it, so a
    // controlled duplicate/null seed lost its selection on a data refresh (round-9 finding 2).
    //
    // Selection is tracked by NODE IDENTITY (reference equality), NOT by Value.
    // Container/parent nodes routinely share a Value (commonly null, or a duplicate
    // across branches); keying selection by Value made a single click light up EVERY
    // node sharing that value (GH #350 — clicking one folder highlighted all
    // value-less folders, incl. a nested one that read as a stray bar among its
    // siblings' children). Reference identity selects exactly the clicked node.
    // The public SelectedValues contract is preserved: values are derived from the
    // selected nodes on the way OUT, and mapped back to nodes on the way IN.
    private HashSet<TreeViewItem<T>> _selectedNodes = new(ReferenceEqualityComparer.Instance);
    // Two pending buckets (see lifecycle above), both drained by TryResolvePendingSelection.
    //
    // _pendingSelectValues — wanted VALUES with no node bound yet: a controlled/seed value for
    // a lazy child not loaded, or for an async/empty first render. Value-based by the
    // SelectedValues contract — an ambiguous (duplicate/null) value binds EVERY match, which is
    // what a value-speaking consumer asked for.
    private List<T>? _pendingSelectValues;
    // _pendingCarries — the structural IDENTITY of a resolved node that VANISHED on an Items
    // refresh (its value-verified index path from the tree it left, plus its value). Kept
    // SEPARATE from the value bucket because its resolution is identity-preserving: on the
    // node's return it re-binds by PATH, falls back to a UNIQUE value, and drops on ambiguity —
    // so a vanished node with a duplicate/null Value re-selects the SAME node, not a same-valued
    // sibling (nor every match). Carrying only the value here lost that identity, re-selecting
    // the first/every value match on return.
    private List<PendingCarry>? _pendingCarries;
    // _seededValues — the VALUES currently owned by a consumer SelectedValues seed (the round-9
    // origin marker). A seeded value keeps VALUE semantics across an Items vanish/return: it re-binds
    // to EVERY match (the value contract) instead of degrading into an identity carry that
    // ambiguity-drops a duplicate/null-valued seed. A value LEAVES this set when the consumer changes
    // SelectedValues, OR when the user interactively takes ownership of it (single-select click clears
    // all; multi-select toggle drops just that value) — after which the selection follows the identity
    // (carry + ambiguity-drop) rules. Distinct from _pendingSelectValues, which is pruned once a value
    // binds; _seededValues persists as the durable origin, so a vanished-then-returned seed is still
    // recognised as value-origin even after it was resolved.
    private HashSet<T>? _seededValues;
    private TreeViewContext? _context;
    // The clicked node's structural PATH, snapshotted in HandleItemClick BEFORE the public OnItemClick
    // callback runs — so HandleSelectionChanged can re-resolve the CURRENT instance if a consumer's
    // OnItemClick handler rebuilt Items (controlled/immutable) in between (round-10 finding 4). The node
    // component awaits OnItemClick before OnSelectionChanged, so without this the selection would add
    // the now-stale (disposed) clicked instance and the fresh rendered row would show as unselected.
    private NodePath? _clickPathBeforeCallback;
    // A vanished resolved node's carried identity: the value-verified root→node PATH it held in the tree
    // it left (index chain + per-level value, round-13 b), plus its Value. The path re-binds the exact
    // node on return; the value is the unique-or-drop fallback when the structure changed and the path no
    // longer walks.
    private sealed record PendingCarry(NodePath Path, T? Value);

    /// <summary>A structural node identity: the root→node child-index chain PLUS the value carried at
    /// EACH level. Every segment is value-verified AND sibling-uniqueness-gated on the way back
    /// (<see cref="WalkPath"/>), so a duplicate/null-valued ANCESTOR that gets reordered can no longer
    /// silently redirect the walk into the wrong subtree while the leaf still passes its own sibling check
    /// (round-13 finding 2). Captured only while the node is present, so <see cref="Indices"/> and
    /// <see cref="Values"/> are always the same length and Values[d] is the node's value at depth d.</summary>
    internal sealed record NodePath(IReadOnlyList<int> Indices, IReadOnlyList<T?> Values);

    // Search filtering renders the ORIGINAL item instances; visibility and
    // search-forced expansion are tracked in these side tables instead of
    // cloned subtrees, so checking/expanding a node while a filter is active
    // mutates the real item and the state survives clearing the search.
    // TreeViewItem is a record (value equality, mutable fields) — reference
    // comparers keep set membership stable across mutations.
    private HashSet<TreeViewItem<T>>? _visibleSet;
    private readonly HashSet<TreeViewItem<T>> _autoExpanded = new(ReferenceEqualityComparer.Instance);

    // ── IN-FLIGHT OWNERSHIP (round-12, canonical-model pillar 5) ─────────────
    // The live registry of lazy-load operations. Each entry is the {path, value, sibling values}
    // snapshot captured when a load set IsLoading; it OWNS whichever node currently occupies that slot,
    // so a rebuild-copied spinner on a fresh @key'd instance stays lit while the op runs and is reaped
    // by SweepOrphanedInFlightFlags once the entry is removed (the load resolved/dropped/failed).
    private sealed record InFlightExpansion(IReadOnlyList<int> Path, T? Value, IReadOnlyList<T?> Siblings)
    {
        /// <summary>Set when a user collapse (second row click / ArrowLeft / collapse-all) lands WHILE this
        /// lazy load is still pending (round-13 finding 3). The load's success completion then attaches the
        /// children (ChildrenLoaded=true) but does NOT re-expand — honoring the collapse as the latest intent
        /// instead of the optimistic IsExpanded=true that BeginToggleExpand set before awaiting. Mutable, and
        /// never part of any equality/lookup (matching is by {path,value}), so this is safe on the record.</summary>
        public bool Superseded { get; set; }
    }
    private List<InFlightExpansion>? _inFlightLoads;

    // ── SELECTION-PATH SNAPSHOT (round-12, canonical-model pillar 6) ─────────
    // The structural index path of each currently-resolved selected node, snapshotted against the tree
    // AFTER every resolution pass. ReanchorSelection reads a vanished node's OLD path from here so an
    // IN-PLACE Items mutation (where _previousItems is the same, already-mutated object) can still
    // reanchor a duplicate-valued node by its path instead of dropping it (round-12 finding 2).
    private Dictionary<TreeViewItem<T>, NodePath> _selectionPaths = new(ReferenceEqualityComparer.Instance);

    // Roving tabindex / keyboard navigation state (WAI-ARIA tree pattern).
    private readonly string _treeId = LumeoIds.New("tree");
    private readonly Dictionary<TreeViewItem<T>, string> _nodeIds = new(ReferenceEqualityComparer.Instance);
    private int _nodeIdSeq;
    private List<TreeViewItem<T>>? _flatVisible;
    private TreeViewItem<T>? _activeItem;

    private string CssClass => Cx.Merge("text-sm", Class);

    protected override void OnInitialized()
    {
        _context = new TreeViewContext(this);
    }

    // Set when a declarative ExpandAll pass needs to pull in lazy children;
    // consumed once by OnParametersSetAsync so the load runs a single time.
    private bool _expandAllNeedsLazyLoad;

    protected override void OnParametersSet()
    {
        if (SelectedValuesChanged.HasDelegate)
        {
            // CONTROLLED: adopt only when SelectedValues is NOT the same object
            // reference we just pushed (reference equality is sufficient: a veto
            // keeps the OLD reference; an echo re-supplies the same list object we
            // handed the parent; a programmatic override supplies a new reference).
            //
            // ALSO a no-op when SelectedValues is unchanged from before this interaction
            // (_previousSelectedValues, read here BEFORE it is overwritten below): an observer-only
            // consumer that binds SelectedValuesChanged purely to react to selection — without also
            // echoing SelectedValues back — leaves the parameter at whatever reference it started with
            // forever, and that re-render must not be treated as the parent clearing the selection.
            // Only a reference that differs from BOTH our own push AND the pre-interaction snapshot is
            // an authoritative, distinguishable veto/reset.
            var isEcho = ReferenceEquals(SelectedValues, _lastPushedSelectedValues);
            var isUnchangedFromBeforeInteraction = ReferenceEquals(SelectedValues, _previousSelectedValues);
            if (!isEcho && !isUnchangedFromBeforeInteraction)
            {
                _selectedNodes = ResolveSelectedNodes(SelectedValues);
                _lastPushedSelectedValues = SelectedValues;
            }
            // else: echo of our own selection, or unchanged from before — keep the in-flight selection.
            _previousSelectedValues = SelectedValues;
        }
        else if (!ReferenceEquals(SelectedValues, _previousSelectedValues))
        {
            // #14: UNCONTROLLED — only re-seed from SelectedValues when the
            // parameter ITSELF changed (new reference). Re-seeding on every
            // OnParametersSet wiped an internally-clicked selection on any
            // unrelated re-render, breaking the two-way-binding contract used
            // elsewhere.
            if (SelectedValues is not null)
                _selectedNodes = ResolveSelectedNodes(SelectedValues);
            _previousSelectedValues = SelectedValues;
        }

        bool referenceChanged = !ReferenceEquals(Items, _previousItems);
        bool expandAllChanged = ExpandAll != _previousExpandAll;
        // Capture the OUTGOING tree before overwriting it — ReanchorSelection needs it
        // to compute each selected node's structural path in the tree it came from.
        var previousItems = _previousItems;
        _previousItems = Items;
        _previousExpandAll = ExpandAll;
        _flatVisible = null;

        // CHANGE DETECTION (canonical model pillar 3): re-resolution must not hinge on the Items
        // list-reference. Run the reanchor/pending/tri-state pass when the reference changed OR a
        // current binding could be stale — so an IN-PLACE mutation of the same list reference
        // (items[i] replaced by a fresh same-valued node) still reanchors the selection onto the
        // new instance instead of stranding _selectedNodes on a disposed one (round-11 d).
        bool needsResolve = referenceChanged || HasStaleOrPendingSelection();

        if (needsResolve)
        {
            // A same-content refresh (new reference-distinct instances) or an in-place swap would
            // drop the identity-tracked selection. Re-anchor to the current instances by structural
            // PATH (so duplicate / null Values don't mis-anchor), with a unique-value fallback — so a
            // reload keeps the selected row highlighted. Vanished nodes carry back to the pending
            // buckets by ORIGIN (seeded=value / interactive=identity), never dropped silently.
            ReanchorSelection(Items ?? [], previousItems);
            // pending → resolved on ANY refresh (not only lazy-load): a seed value for a node that
            // only just materialized — an async/empty first render, or a value carried forward when
            // its node vanished — binds against the current tree.
            TryResolvePendingSelection(Items);
            // TRI-STATE DERIVE-ON-SEED: recompute every parent's checked/indeterminate state from its
            // (seeded or freshly-assigned) children so a tree that arrives with children already
            // IsChecked=true shows the correct parent state on the FIRST render — not just after an
            // interactive check. Same recompute the interactive path (HandleItemCheck) uses, so both
            // routes agree. Cascade-only: when CascadeCheck is off, parent/child checks are
            // independent by contract, so no derivation runs.
            if (CascadeCheck && ShowCheckboxes)
                UpdateAncestorStates(Items ?? []);
            // Round-12 finding 1 (canonical-model pillar 5): after the reanchor/resolution pass, reap any
            // optimistic in-flight flag a controlled rebuild copied onto a fresh @key'd instance whose
            // originating load is no longer live — no code path owns that spinner otherwise.
            SweepOrphanedInFlightFlags();
        }

        if (referenceChanged)
        {
            if (ExpandAll)
            {
                ApplyExpandAll(Items ?? [], true);
                // #201: with lazy children, also fetch the not-yet-loaded branches.
                if (LoadChildren is not null)
                    _expandAllNeedsLazyLoad = true;
            }
            // Only a reference swap can move which instances the render walks; an in-place mutation
            // keeps _displayItems pointing at the same (now-mutated) list, so the reanchored
            // selection above is reflected on the next render without re-filtering (which would also
            // clear search auto-expansion).
            RebuildDisplay();
        }
        else if (expandAllChanged)
        {
            ApplyExpandAll(Items ?? [], ExpandAll);
            if (ExpandAll && LoadChildren is not null)
                _expandAllNeedsLazyLoad = true;
            RebuildDisplay();
        }
        else if (!string.IsNullOrWhiteSpace(_searchText))
        {
            // Round-13 finding 1 (extends round-12 finding 4): while a SEARCH FILTER is active,
            // _displayItems is a filtered ToList() SNAPSHOT — NOT the live Items — so an IN-PLACE mutation
            // of the same list reference (retitling or replacing items[i]) never reaches the render until
            // the display is re-materialized. The prior guard gated this on needsResolve, i.e. only when a
            // SELECTION/pending binding looked stale; a filtered tree with NO selection left the stale rows
            // on screen because nothing rebuilt _displayItems. Change detection must NOT hinge on selection
            // state (pillar 3): whenever a filter is active and neither the Items reference nor ExpandAll
            // changed, ALWAYS re-materialize the filtered display.
            //
            // Tradeoff (documented, pillar 3): detecting an in-place CONTENT edit (a retitle) with no
            // reference change and no selection needs either a structural fingerprint of the whole tree or
            // an unconditional re-filter. CollectVisible is already O(n) and only runs while a filter is
            // live (a transient user state), so the unconditional re-filter is both simpler and cheaper to
            // maintain than a fingerprint. RebuildDisplay is idempotent — it recomputes _visibleSet and
            // _autoExpanded from scratch — so a redundant rebuild on an unrelated re-render is pure
            // recompute with no state loss.
            RebuildDisplay();
        }

        // Snapshot the settled selection's paths against the CURRENT tree — these become the OLD paths a
        // later IN-PLACE mutation reanchors against (pillar 6), captured while the nodes are still present.
        SnapshotSelectionPaths();
    }

    /// <summary>Whether the reanchor/pending pass should run even when the <see cref="Items"/>
    /// list reference is UNCHANGED (round-11 d — an in-place mutation of the same list). True when a
    /// pending bucket still holds an unbound value/carry, or when any selected node instance is no
    /// longer reachable in the current tree (a fresh instance replaced it in place). O(n) in the tree
    /// size, but only reached on a same-reference re-render that also carries selection/pending state
    /// — a selection-free tree or a reference swap short-circuits before the flatten.</summary>
    private bool HasStaleOrPendingSelection()
    {
        if (_pendingSelectValues is { Count: > 0 } || _pendingCarries is { Count: > 0 }) return true;
        if (_selectedNodes.Count == 0) return false;
        var flat = new List<TreeViewItem<T>>();
        FlattenAll(Items ?? [], flat);
        var present = new HashSet<TreeViewItem<T>>(flat, ReferenceEqualityComparer.Instance);
        foreach (var sel in _selectedNodes)
            if (!present.Contains(sel)) return true;
        return false;
    }

    protected override async Task OnParametersSetAsync()
    {
        if (!_expandAllNeedsLazyLoad) return;
        _expandAllNeedsLazyLoad = false;
        var gen = ++_expandGeneration;
        await LoadAndExpandAllAsync(Items ?? [], gen);
        if (gen != _expandGeneration) return; // superseded by a collapse/expand
        // Lazy branches just materialized — derive parents from their (possibly seeded) checks.
        if (CascadeCheck && ShowCheckboxes)
            UpdateAncestorStates(Items ?? []);
        _flatVisible = null;
        RebuildDisplay();
        StateHasChanged();
    }

    /// <summary>Expands every node in the tree. Already-loaded nodes expand
    /// synchronously; when <see cref="LoadChildren"/> is configured, lazy children
    /// are then fetched and expanded in the background. Await
    /// <see cref="ExpandAllNodesAsync"/> instead when you need the lazy load to
    /// complete before continuing.</summary>
    public void ExpandAllNodes()
    {
        ApplyExpandAll(Items ?? [], true);
        _flatVisible = null;
        StateHasChanged();

        // #201: ExpandAll must also pull in lazily-loaded children. Fire-and-forget
        // so the synchronous void contract is preserved; the async pass re-renders
        // as each level resolves.
        if (LoadChildren is not null)
            _ = ExpandAllNodesAsync();
    }

    /// <summary>Expands every node, awaiting <see cref="LoadChildren"/> for any
    /// not-yet-loaded lazy branches so the whole tree is realized on completion.</summary>
    // Bumped on every expand-all / collapse-all so a stale background lazy-expand
    // pass (started before a later collapse) detects it lost the race and bails
    // instead of re-expanding the tree the user just collapsed.
    private int _expandGeneration;

    public async Task ExpandAllNodesAsync()
    {
        var gen = ++_expandGeneration;
        ApplyExpandAll(Items ?? [], true);
        if (LoadChildren is not null)
            await LoadAndExpandAllAsync(Items ?? [], gen);
        if (gen != _expandGeneration) return; // superseded by a newer expand/collapse
        // Lazy branches just materialized — derive parents from their (possibly seeded) checks.
        if (CascadeCheck && ShowCheckboxes)
            UpdateAncestorStates(Items ?? []);
        _flatVisible = null;
        StateHasChanged();
    }

    public void CollapseAllNodes()
    {
        _expandGeneration++; // cancel any in-flight lazy expand-all pass (LoadAndExpandAllAsync bails on gen)
        ApplyExpandAll(Items ?? [], false);
        // Per-node lazy loads (row-click / chevron via LoadChildrenThenNotifyAsync) are NOT gated by
        // _expandGeneration, so a collapse-all while one is pending must ALSO supersede it — otherwise its
        // success completion re-expands the node the user just collapsed (round-13 finding 3, sweep site).
        SupersedeAllInFlight();
        _flatVisible = null;
        StateHasChanged();
    }

    /// <summary>Recursively expands nodes, fetching lazy children via
    /// <see cref="LoadChildren"/> for branches that haven't been loaded yet, then
    /// descending into the freshly-loaded subtrees. Re-renders after each fetch so
    /// the tree fills in progressively. Safe when <see cref="LoadChildren"/> is null
    /// (it simply recurses over already-loaded children).</summary>
    private async Task LoadAndExpandAllAsync(List<TreeViewItem<T>> items, int gen)
    {
        foreach (var item in items)
        {
            if (gen != _expandGeneration) return; // a newer collapse/expand superseded us
            item.IsExpanded = true;

            // The node whose children we descend into after this level. Defaults to `item`; the lazy load
            // below re-resolves it to the fresh @key'd instance when a controlled/immutable rebuild replaced
            // `item` mid-load, so BOTH the attach and the recursion follow the LIVE tree (round-13 finding 4).
            var target = item;

            // A lazy, not-yet-loaded, non-leaf branch: fetch it once.
            if (LoadChildren is not null && !item.ChildrenLoaded && !item.IsLeaf
                && item.Children is not { Count: > 0 })
            {
                item.IsLoading = true;
                // Register in-flight ownership (pillar 5) so a resolution-pass sweep that fires mid
                // expand-all doesn't reap this genuine spinner — a node may carry IsLoading only while an
                // entry owns its slot. Removed + swept in the finally.
                var loadPath = GetNodePath(item);
                var loadIndices = loadPath?.Indices ?? [];
                (_inFlightLoads ??= []).Add(new InFlightExpansion(loadIndices, item.Value, SiblingValuesAt(loadIndices)));
                _flatVisible = null;
                StateHasChanged();
                try
                {
                    var loaded = await LoadChildren(item);
                    // Bail if the user collapsed / re-expanded while we awaited — don't
                    // resurrect a tree they just collapsed (finally resets IsLoading).
                    if (gen != _expandGeneration) return;
                    // SUCCESS RE-RESOLUTION (round-13 finding 4): mirror the per-row lazy path
                    // (ResolveExpansionTarget). A controlled/immutable parent can rebuild Items while the
                    // loader is pending — disposing THIS @key'd node and copying its optimistic
                    // IsLoading/IsExpanded onto a fresh instance. Attaching to the stale `item` would strand
                    // that fresh row expanded-but-empty AND recurse into an orphaned subtree. Re-resolve to
                    // the CURRENT instance; when identity is UNPROVABLE among duplicate/null-valued siblings,
                    // DROP this branch's load — the finally clears the stale spinner and sweeps the copied one
                    // off the fresh row (re-fetchable on the next expand beats a mis-attach, round-11 b).
                    var resolved = ResolveExpansionTarget(item, loadPath);
                    if (resolved is null)
                        continue; // ambiguous identity → drop this branch's load; finally sweeps the fresh spinner
                    target = resolved;
                    target.Children = loaded;
                    target.ChildrenLoaded = true;
                    // Honor a collapse that landed mid-load (round-13 finding 3): re-expand only when the op
                    // wasn't superseded. Otherwise leave the branch collapsed but with its children attached.
                    if (!IsInFlightSuperseded(loadPath, item.Value))
                        target.IsExpanded = true;
                    // Clear the spinner on the RESOLVED node too (a rebuild may have copied IsLoading=true
                    // onto the fresh instance); the finally below only clears the stale item.
                    target.IsLoading = false;
                    // Bind any pending controlled/seed selection naming one of the
                    // just-loaded nodes (same as the per-node expand path).
                    TryResolvePendingSelection(target.Children);
                    // Mirror the per-node lazy-load cascade (rc.42): a fully-checked
                    // parent propagates its check to freshly-loaded children.
                    if (target.IsChecked && !target.IsIndeterminate && target.Children is { Count: > 0 })
                        SetChildrenChecked(target.Children, true);
                }
                finally
                {
                    item.IsLoading = false;
                    RemoveInFlight(loadIndices, item.Value);
                    // Reap any optimistic spinner a controlled rebuild copied onto a fresh @key'd instance
                    // now that this entry is gone — the expand-all mirror of CompleteInFlightExpansion's
                    // post-removal sweep on the per-row path. Without it a dropped/rebuilt expand-all load
                    // strands the copied spinner on the fresh row forever (round-13 finding 4).
                    SweepOrphanedInFlightFlags();
                }
            }

            if (target.Children is { Count: > 0 })
                await LoadAndExpandAllAsync(target.Children, gen);
        }
    }

    private async Task HandleItemClick(TreeViewItem<T> item)
    {
        // Snapshot the clicked node's structural path NOW — before the public OnItemClick can rebuild
        // Items — so the selection callback that fires next (HandleSelectionChanged) can re-resolve the
        // fresh @key'd instance the rebuild produced instead of adding the stale one (round-10 finding 4).
        _clickPathBeforeCallback = GetNodePath(item);
        await OnItemClick.InvokeAsync(item);
    }

    private async Task HandleItemCheck(TreeViewItem<T> item)
    {
        if (CascadeCheck && ShowCheckboxes)
        {
            SetChildrenChecked(item.Children, item.IsChecked);
            UpdateAncestorStates(Items ?? []);
        }
        await OnItemCheck.InvokeAsync(item);

        if (CheckedValuesChanged.HasDelegate)
        {
            var allChecked = CollectChecked(Items ?? []);
            await CheckedValuesChanged.InvokeAsync(allChecked);
        }

        StateHasChanged();
    }

    private Task HandleExpandChanged(TreeViewItem<T> item)
    {
        // A manual collapse overrides any search-forced expansion.
        if (!item.IsExpanded)
        {
            _autoExpanded.Remove(item);
        }
        else
        {
            // Expanding may have just lazy-loaded this node's children (TreeViewNode
            // assigns Item.Children before raising this). Bind any pending controlled/
            // seed selection that named one of those now-materialized nodes.
            TryResolvePendingSelection(item.Children);
            // A lazy branch can materialize with children already IsChecked=true (seeded
            // in the loaded data), which changes this parent's — and its ancestors' —
            // derived tri-state. Recompute the whole chain so a freshly-loaded checked
            // subtree lifts its parents to indeterminate/checked. Cascade-only (see the
            // derive-on-seed note in OnParametersSet). TreeViewNode's own post-load cascade
            // only pushes a fully-checked parent DOWN onto its new children; this pass is
            // what derives parents UP from the loaded state.
            if (CascadeCheck && ShowCheckboxes)
                UpdateAncestorStates(Items ?? []);
        }
        _flatVisible = null;
        // A lazy load may have just bound a pending selection onto a newly-materialized node; refresh the
        // path snapshot so a subsequent in-place mutation reanchors it (pillar 6).
        SnapshotSelectionPaths();
        StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task HandleSelectionChanged(TreeViewItem<T> item)
    {
        // Selection is by node identity, so clicking a container node with a null or
        // duplicate Value selects ONLY that node — never every node that happens to
        // share its value. This selection path never touches IsExpanded: expansion is
        // owned by the chevron, the Left/Right keys, and (when ExpandOnRowClick is on)
        // the separate ToggleExpand call in TreeViewNode.HandleClick — so selecting a
        // node and expanding it stay decoupled here (a parent can be selected while
        // collapsed and vice-versa).
        //
        // Re-resolve the clicked instance against the CURRENT tree first (round-10 finding 4): a
        // consumer's OnItemClick handler (awaited BEFORE this callback in TreeViewNode.HandleClick) may
        // have rebuilt Items (controlled/immutable), disposing the clicked @key'd node — adding the stale
        // instance would leave the fresh rendered row unselected. The canonical resolver runs in STRICT
        // SELECTION mode: reference-identity → value-verified path (snapshotted in HandleItemClick) →
        // tree-unique value → DROP. It never positional-guesses, so a duplicate/null-valued click whose
        // siblings were reordered during OnItemClick selects NOTHING rather than the wrong same-valued
        // sibling (round-11 a) — the ambiguity-DROP convention. In the common (no-rebuild) case the
        // instance is still present, so this returns it unchanged.
        var resolvedClick = ResolveNode(item, _clickPathBeforeCallback, item.Value, NodeResolveMode.Selection);
        _clickPathBeforeCallback = null;
        if (resolvedClick is null)
        {
            // Identity unprovable after a rebuild — drop this click's selection change (keep the prior
            // selection). Re-render so the fresh rows reflect the settled selection state.
            StateHasChanged();
            return;
        }
        item = resolvedClick;
        bool changed;
        if (MultiSelect)
        {
            // Toggle membership (reference identity).
            if (!_selectedNodes.Add(item))
                _selectedNodes.Remove(item);
            changed = true;
            // Supersede (multi-select): an explicit user action on THIS value wins over a
            // deferred seed for the same value, but the seed's OTHER pending values stay
            // wanted — a multi-select seed is a set the user is editing, not replacing.
            RemovePending(item.Value);
        }
        else
        {
            // Replace the selection; re-clicking the same node instance is a no-op.
            changed = _selectedNodes.Count != 1 || !_selectedNodes.Contains(item);
            if (changed)
            {
                _selectedNodes.Clear();
                _selectedNodes.Add(item);
            }
            // Supersede (single-select): the click now owns the entire selection, so a
            // pending lazy seed (which represented the intended sole selection) is void —
            // clear it unconditionally so it can't resurrect and co-select once its branch
            // loads. Unconditional: even a no-op re-click asserts sole ownership. A carried
            // identity (a vanished prior selection) is void for the same reason. The click also
            // takes the whole selection INTERACTIVE, so every seed origin is cleared — a later
            // vanish/return now follows identity (carry + ambiguity-drop), not value re-binding.
            _pendingSelectValues = null;
            _pendingCarries = null;
            _seededValues = null;
        }

        if (changed && SelectedValuesChanged.HasDelegate)
        {
            // Public contract stays value-based: project the selected nodes to values.
            List<T> outgoing = [.._selectedNodes.Select(n => n.Value!)];
            // Record _lastPushedSelectedValues BEFORE invoking SelectedValuesChanged:
            // a controlled parent re-renders synchronously inside InvokeAsync, so
            // OnParametersSet must already see this exact list reference as "the
            // selection we just pushed" to distinguish an accepted echo (keep the
            // in-flight selection) from a veto (parent kept its old value → roll back).
            _lastPushedSelectedValues = outgoing;
            await SelectedValuesChanged.InvokeAsync(outgoing);
        }
        // Capture the clicked selection's path against the current tree so a following in-place mutation
        // reanchors it by path (pillar 6). InvokeAsync above may have rebuilt Items via a controlled
        // parent; SnapshotSelectionPaths reads whatever tree is current now.
        SnapshotSelectionPaths();
        StateHasChanged();
    }

    private void OnSearchInput(ChangeEventArgs e)
    {
        _searchText = e.Value?.ToString() ?? "";
        RebuildDisplay();
    }

    private void RebuildDisplay()
    {
        _flatVisible = null;
        _autoExpanded.Clear();

        if (string.IsNullOrWhiteSpace(_searchText))
        {
            _visibleSet = null;
            _displayItems = Items ?? [];
        }
        else
        {
            _visibleSet = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
            CollectVisible(Items ?? [], _searchText, _visibleSet, _autoExpanded);
            _displayItems = (Items ?? []).Where(_visibleSet.Contains).ToList();
        }
    }

    /// <summary>Marks every item whose text matches the filter — or that has a matching
    /// descendant — as visible. A text-matching item keeps its whole subtree visible;
    /// ancestors of deeper matches are force-expanded via <see cref="_autoExpanded"/>
    /// without mutating their persisted <c>IsExpanded</c> state. Returns whether
    /// anything in <paramref name="items"/> matched.</summary>
    private static bool CollectVisible(List<TreeViewItem<T>> items, string filter,
        HashSet<TreeViewItem<T>> visible, HashSet<TreeViewItem<T>> autoExpanded)
    {
        bool any = false;
        foreach (var item in items)
        {
            bool selfMatches = item.Text.Contains(filter, StringComparison.OrdinalIgnoreCase);
            bool childMatches = item.Children is { Count: > 0 }
                && CollectVisible(item.Children, filter, visible, autoExpanded);

            if (!selfMatches && !childMatches) continue;

            visible.Add(item);
            any = true;
            if (childMatches)
                autoExpanded.Add(item);
            else if (item.Children is { Count: > 0 })
                MarkSubtreeVisible(item.Children, visible);
        }
        return any;
    }

    private static void MarkSubtreeVisible(List<TreeViewItem<T>> items, HashSet<TreeViewItem<T>> visible)
    {
        foreach (var item in items)
        {
            visible.Add(item);
            if (item.Children is { Count: > 0 })
                MarkSubtreeVisible(item.Children, visible);
        }
    }

    // ---- Shared state consumed by TreeViewNode through the cascaded context ----

    internal bool IsEffectivelyExpanded(TreeViewItem<T> item)
        => item.IsExpanded || _autoExpanded.Contains(item);

    internal IReadOnlyList<TreeViewItem<T>> GetVisibleChildren(TreeViewItem<T> item)
    {
        if (item.Children is not { Count: > 0 }) return [];
        return _visibleSet is null
            ? item.Children
            : item.Children.Where(_visibleSet.Contains).ToList();
    }

    /// <summary>Deterministic per-item element id used as the focus target for
    /// keyboard navigation. Stable for the lifetime of the component.</summary>
    internal string GetNodeId(TreeViewItem<T> item)
    {
        if (!_nodeIds.TryGetValue(item, out var id))
        {
            id = $"{_treeId}-node-{_nodeIdSeq++}";
            _nodeIds[item] = id;
        }
        return id;
    }

    /// <summary>Roving tabindex: exactly one visible node (the active one) is in
    /// the tab sequence; every other node is reachable via arrow keys.</summary>
    internal int GetTabIndex(TreeViewItem<T> item)
    {
        EnsureFlatVisible();
        return ReferenceEquals(item, _activeItem) ? 0 : -1;
    }

    /// <summary>Keeps the roving tabindex in sync when a node receives DOM focus
    /// directly (mouse click or Tab) rather than via arrow-key navigation.</summary>
    internal void SetActive(TreeViewItem<T> item)
    {
        if (ReferenceEquals(_activeItem, item)) return;
        _activeItem = item;
        StateHasChanged();
    }

    /// <summary>WAI-ARIA tree navigation. Down/Up move through the visible nodes in
    /// depth-first order, Home/End jump to the first/last visible node, Right moves
    /// into the first child of an expanded node and Left moves to the parent of a
    /// collapsed/leaf node (the expand/collapse halves of Right/Left are handled in
    /// <see cref="TreeViewNode{T}"/> where the item is mutated).</summary>
    internal async Task HandleNavigationKeyAsync(TreeViewItem<T> item, string key)
    {
        EnsureFlatVisible();
        var flat = _flatVisible!;
        if (flat.Count == 0) return;
        var index = flat.FindIndex(i => ReferenceEquals(i, item));
        if (index < 0) return;

        var target = key switch
        {
            "ArrowDown" => index < flat.Count - 1 ? flat[index + 1] : null,
            "ArrowUp"   => index > 0 ? flat[index - 1] : null,
            "Home"      => flat[0],
            "End"       => flat[^1],
            "ArrowRight" => IsEffectivelyExpanded(item) ? GetVisibleChildren(item).FirstOrDefault() : null,
            "ArrowLeft"  => FindParent(Items ?? [], item),
            _ => null
        };

        if (target is not null && !ReferenceEquals(target, item))
        {
            _activeItem = target;
            StateHasChanged();
            await Interop.FocusElement(GetNodeId(target));
        }
    }

    private void EnsureFlatVisible()
    {
        if (_flatVisible is not null) return;
        _flatVisible = [];
        AppendVisible(_displayItems, _flatVisible);
        if (_activeItem is null || !_flatVisible.Any(i => ReferenceEquals(i, _activeItem)))
        {
            // #13: an Items refresh with new (reference-distinct) instances drops
            // the old _activeItem out of _flatVisible. Re-anchor the roving
            // tabindex by STABLE identity (Value) so keyboard focus survives a
            // same-content refresh instead of snapping back to the first node.
            var byValue = _activeItem is not null
                ? _flatVisible.FirstOrDefault(i => EqualityComparer<T>.Default.Equals(i.Value, _activeItem.Value))
                : null;
            _activeItem = byValue ?? (_flatVisible.Count > 0 ? _flatVisible[0] : null);
        }
    }

    private void AppendVisible(IReadOnlyList<TreeViewItem<T>> items, List<TreeViewItem<T>> result)
    {
        foreach (var item in items)
        {
            result.Add(item);
            if (IsEffectivelyExpanded(item) && item.Children is { Count: > 0 })
                AppendVisible(GetVisibleChildren(item), result);
        }
    }

    private static TreeViewItem<T>? FindParent(List<TreeViewItem<T>> items, TreeViewItem<T> child)
    {
        foreach (var item in items)
        {
            if (item.Children is not { Count: > 0 }) continue;
            if (item.Children.Any(c => ReferenceEquals(c, child))) return item;
            var found = FindParent(item.Children, child);
            if (found is not null) return found;
        }
        return null;
    }

    /// <summary>Maps an incoming (controlled/seed) <see cref="SelectedValues"/> list to
    /// the concrete node instances that carry those values. Value-based on the way IN by
    /// design — a controlled consumer speaks in values; if it supplies an ambiguous value
    /// (null or a duplicate) every matching node is selected, which is the value contract.
    /// Interactive clicks never round-trip through here, so they stay identity-exact.</summary>
    private HashSet<TreeViewItem<T>> ResolveSelectedNodes(List<T>? values)
    {
        // A fresh authoritative SelectedValues redefines the whole selection — any carried
        // identity queued from the PREVIOUS selection is void.
        _pendingCarries = null;
        var set = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
        if (values is not { Count: > 0 })
        {
            _pendingSelectValues = null;
            _seededValues = null;
            return set;
        }
        // Every value in a consumer SelectedValues is a SEED (value origin). Record them so a later
        // Items vanish/return re-binds by value (round-9), independent of _pendingSelectValues pruning.
        _seededValues = new HashSet<T>(values);
        var wanted = new HashSet<T>(values);
        CollectMatching(Items ?? [], wanted, set);
        // Remember the values that named a not-yet-materialized (lazy) node so they can be resolved
        // when that branch loads. A value that matched at least one visible node is normally
        // satisfied — BUT while the tree still has UNLOADED lazy branches a same-valued node may yet
        // materialize behind LoadChildren, and the public value contract selects EVERY node carrying
        // a requested value (not just the first). So until the tree is fully materialized we hold
        // ALL requested values pending — matched ones included — and re-apply them additively to each
        // subtree as it loads (TryResolvePendingSelection). Only once no lazy branch remains does a
        // matched value drop out of pending (Codex round-7 finding 2).
        var matched = new HashSet<T>(set.Select(n => n.Value!));
        var pending = HasUnloadedLazyBranches(Items ?? [])
            ? values.Distinct().ToList()
            : values.Where(v => !matched.Contains(v)).ToList();
        _pendingSelectValues = pending.Count > 0 ? pending : null;
        return set;
    }

    /// <summary>Drains both pending buckets. Path-carried IDENTITIES (vanished resolved nodes)
    /// re-bind first — by their value-verified path in the CURRENT full tree, falling back to a
    /// unique value and dropping on ambiguity — so a returning node with a duplicate/null Value
